struct ComponentBuilder {
  typedef Component Table;
  ::flatbuffers::FlatBufferBuilder &fbb_;
  ::flatbuffers::uoffset_t start_;
  void add_component_type(SE::FlatBuffers::ComponentU component_type) {
    fbb_.AddElement<uint8_t>(Component::VT_COMPONENT_TYPE, static_cast<uint8_t>(component_type), 0);
  }
  void add_component(::flatbuffers::Offset<void> component) {
    fbb_.AddOffset(Component::VT_COMPONENT, component);
  }
  explicit ComponentBuilder(::flatbuffers::FlatBufferBuilder &_fbb)
        : fbb_(_fbb) {
    start_ = fbb_.StartTable();
  }
  ::flatbuffers::Offset<Component> Finish() {
    const auto end = fbb_.EndTable(start_);
    auto o = ::flatbuffers::Offset<Component>(end);
    fbb_.Required(o, Component::VT_COMPONENT);
    return o;
  }
};

inline ::flatbuffers::Offset<Component> CreateComponent(
    ::flatbuffers::FlatBufferBuilder &_fbb,
    SE::FlatBuffers::ComponentU component_type = SE::FlatBuffers::ComponentU::NONE,
    ::flatbuffers::Offset<void> component = 0) {
  ComponentBuilder builder_(_fbb);
  builder_.add_component(component);
  builder_.add_component_type(component_type);
  return builder_.Finish();
}

inline bool VerifyColliderU(::flatbuffers::Verifier &verifier, const void *obj, ColliderU type) {
  switch (type) {
    case ColliderU::NONE: {
      return true;
    }
    case ColliderU::BoxCollider: {
      auto ptr = reinterpret_cast<const SE::FlatBuffers::BoxCollider *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case ColliderU::SphereCollider: {
      auto ptr = reinterpret_cast<const SE::FlatBuffers::SphereCollider *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case ColliderU::CapsuleCollider: {
      auto ptr = reinterpret_cast<const SE::FlatBuffers::CapsuleCollider *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case ColliderU::MeshCollider: {
      auto ptr = reinterpret_cast<const SE::FlatBuffers::MeshCollider *>(obj);
      return verifier.VerifyTable(ptr);
    }
    default: return true;
  }
}

inline bool VerifyColliderUVector(::flatbuffers::Verifier &verifier, const ::flatbuffers::Vector<::flatbuffers::Offset<void>> *values, const ::flatbuffers::Vector<ColliderU> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (::flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyColliderU(
        verifier,  values->Get(i), types->GetEnum<ColliderU>(i))) {
      return false;
    }
  }
  return true;
}

inline bool VerifyComponentU(::flatbuffers::Verifier &verifier, const void *obj, ComponentU type) {
  switch (type) {
    case ComponentU::NONE: {
      return true;
    }
    case ComponentU::StaticModel: {
      auto ptr = reinterpret_cast<const SE::FlatBuffers::StaticModel *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case ComponentU::AnimatedModel: {
      auto ptr = reinterpret_cast<const SE::FlatBuffers::AnimatedModel *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case ComponentU::RigidBody: {
      auto ptr = reinterpret_cast<const SE::FlatBuffers::RigidBody *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case ComponentU::AudioEmitter: {
      auto ptr = reinterpret_cast<const SE::FlatBuffers::AudioEmitter *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case ComponentU::AudioListener: {
      auto ptr = reinterpret_cast<const SE::FlatBuffers::AudioListener *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case ComponentU::SoundEmitter: {
      auto ptr = reinterpret_cast<const SE::FlatBuffers::SoundEmitter *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case ComponentU::AppComponent: {
      auto ptr = reinterpret_cast<const SE::FlatBuffers::AppComponent *>(obj);
      return verifier.VerifyTable(ptr);
    }
    default: return true;
  }
}

inline bool VerifyComponentUVector(::flatbuffers::Verifier &verifier, const ::flatbuffers::Vector<::flatbuffers::Offset<void>> *values, const ::flatbuffers::Vector<ComponentU> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (::flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyComponentU(
        verifier,  values->Get(i), types->GetEnum<ComponentU>(i))) {
      return false;
    }
  }
  return true;
}

